188→// Fetch blog post for static generation
189→export async function getBlogPost(slug: string) {
190→  try {
191→    const postData = await basehub.query({
192→      blog: {
193→        posts: {
194→          __args: { first: 1, filter: { _sys_slug: { eq: slug } } },
195→          items: {
196→            _id: true,
197→            _title: true,
198→            _slug: true,
199→            date: true,
200→            isvisible: true,
201→            coverImage: {
202→              url: true,
203→              alt: true,
204→            },
205→            author: {
206→              _title: true,
207→              avatar: {
208→                url: true,
209→                alt: true,
210→              },
211→            },
212→            body: {
213→              plainText: true,
214→              json: {
215→                content: true,
216→              },
217→              html: true,
218→              markdown: true,
219→              readingTime: true,
220→            },
221→          },
222→        },
223→      },
224→    });
225→
226→    const [post] = postData.blog.posts.items;
227→    return post;
228→  } catch (error) {
229→    console.error("❌ Error fetching blog post:", error);
230→    return null;
231→  }
232→}
