101→interface IBlurImage {
102→  height?: string;
103→  width?: string;
104→  src?: string;
105→  className?: string;
106→  alt?: string;
107→}
108→
109→export const BlurImage = ({
110→  height,
111→  width,
112→  src,
113→  className,
114→  alt,
115→}: IBlurImage) => {
116→  const [isLoading, setLoading] = useState(true);
117→  return (
118→    <BaseHubImage
119→      alt={alt || "Blog post image"}
120→      className={cn(
121→        "transform transition duration-300",
122→        isLoading ? "scale-105 blur-sm" : "scale-100 blur-0",
123→        className,
124→      )}
125→      height={Number.parseInt(height || "400")}
126→      onLoad={() => setLoading(false)}
127→      src={src || ""}
128→      width={Number.parseInt(width || "600")}
129→    />
130→  );
131→};
