import { cn } from "@/lib/utils";

interface LandingContainerProps {
  children: React.ReactNode;
  className?: string; // Applied to the <section>
  id?: string;
  containerClassName?: string; // Applied to the max-width <div>
  background?: React.ReactNode;
}

export function LandingContainer({
  children,
  className,
  id,
  containerClassName,
  background,
}: LandingContainerProps) {
  return (
    <section
      id={id}
      className={cn(
        "relative flex flex-col items-center justify-center self-stretch scroll-mt-24 py-12 sm:py-16",
        className,
      )}
    >
      {background}
      <div
        className={cn(
          "relative z-10 flex w-full max-w-[1400px] flex-col items-center justify-start gap-6 sm:gap-8 px-4 sm:px-6 md:px-20 min-w-0",
          containerClassName,
        )}
      >
        {children}
      </div>
    </section>
  );
}

export const LANDING_TYPOGRAPHY = {
  h1: "text-center text-black text-3xl sm:text-4xl md:text-[70px] font-bold font-display leading-tight md:leading-[1.1] tracking-[-1.4px]",
  h2: "text-center text-black text-3xl sm:text-4xl md:text-5xl font-medium font-display leading-tight md:leading-[1.1]",
  subtitle:
    "text-center text-neutral-600 text-base sm:text-lg md:text-xl font-medium font-body max-w-[700px]",
};

