"use client";

import Link from "next/link";
import { useState } from "react";
import { Logo } from "@/components/logo";

const NAV_LINKS = [
  { label: "Pricing", href: "#pricing" },
  { label: "Features", href: "#features" },
  { label: "FAQ", href: "#faq" },
];

export function Navbar() {
  const [mobileOpen, setMobileOpen] = useState(false);

  return (
    <header className="sticky top-0 z-50 px-3 py-3 sm:px-4 sm:py-4 md:px-6">
      <div className="w-full max-w-[1280px] mx-auto p-3 sm:p-5 bg-[#eaeaea] rounded-2xl sm:rounded-[20px] flex justify-between items-center gap-2 sm:gap-4 min-w-0">
        {/* Logo */}
        <Logo href="/" />

        {/* Desktop Nav */}
        <nav className="hidden md:flex justify-center items-center gap-10 flex-1">
          {NAV_LINKS.map((link) => (
            <Link
              key={link.label}
              href={link.href}
              className="text-black text-base font-medium font-display leading-6 hover:text-gray-600 transition-colors"
            >
              {link.label}
            </Link>
          ))}
        </nav>

        {/* CTA + Mobile hamburger */}
        <div className="flex items-center gap-3">
          <Link
            href="/sign-in"
            className="hidden sm:inline-flex px-5 py-2.5 bg-black rounded-lg text-white text-base font-medium font-display leading-6 hover:bg-gray-800 transition-all active:scale-95 justify-center items-center"
          >
            Get Started
          </Link>
          <button
            className="md:hidden flex flex-col gap-1.5 p-1 rounded-md hover:bg-black/5 transition-colors"
            onClick={() => setMobileOpen(!mobileOpen)}
            type="button"
            aria-expanded={mobileOpen}
            aria-label="Toggle menu"
          >
            <span
              className={`w-6 h-0.5 bg-black transition-all ${mobileOpen ? "rotate-45 translate-y-2" : ""}`}
            />
            <span
              className={`w-6 h-0.5 bg-black transition-all ${mobileOpen ? "opacity-0" : ""}`}
            />
            <span
              className={`w-6 h-0.5 bg-black transition-all ${mobileOpen ? "-rotate-45 -translate-y-2" : ""}`}
            />
          </button>
        </div>
      </div>

      {/* Mobile menu */}
      {mobileOpen && (
        <div className="md:hidden mt-2 mx-auto w-full max-w-[1280px] p-4 bg-[#eaeaea] rounded-2xl flex flex-col gap-1 px-3 sm:px-4">
          {NAV_LINKS.map((link) => (
            <Link
              key={link.label}
              href={link.href}
              className="py-3 px-2 font-medium text-base font-display border-b border-black/10 last:border-0"
              onClick={() => setMobileOpen(false)}
            >
              {link.label}
            </Link>
          ))}
          <Link
            href="/sign-in"
            className="mt-2 w-full bg-black text-white h-12 flex items-center justify-center rounded-lg font-medium font-display"
            onClick={() => setMobileOpen(false)}
          >
            Get Started
          </Link>
        </div>
      )}
    </header>
  );
}

