import type { Metadata } from "next";
import { PostCard } from "@/components/blog/post-card";
import { getAllBlogPosts } from "@/lib/basehub.action";
import { Footer } from "../_components/footer";
import { Navbar } from "../_components/navbar";

export const dynamic = "force-static";

export const metadata: Metadata = {
  title: "Blog | RunAgents",
  description:
    "Latest updates, tutorials, and insights from the RunAgents team.",
  openGraph: {
    title: "Blog | RunAgents",
    description:
      "Latest updates, tutorials, and insights from the RunAgents team.",
    url: "/blog",
  },
};

export default async function BlogPage() {
  const posts = await getAllBlogPosts();

  return (
    <div className="min-h-screen bg-white text-black font-display selection:bg-black selection:text-white overflow-x-hidden">
      <Navbar />
      <main className="mx-auto w-full max-w-[1200px] px-4 py-12 sm:px-6 sm:py-16">
        <h1 className="mb-8 font-display text-3xl font-bold text-black sm:text-4xl md:text-5xl">
          Blog
        </h1>
        {posts.length === 0 ? (
          <p className="text-neutral-500">
            No posts published yet. Check back soon.
          </p>
        ) : (
          <div className="grid gap-8 sm:grid-cols-2 lg:grid-cols-3">
            {posts.map((post) => (
              <PostCard key={post._id} post={post} />
            ))}
          </div>
        )}
      </main>
      <Footer />
    </div>
  );
}

