}

export function PostBody({ content }: PostBodyProps) {
  return (
    <div className="prose prose-neutral mx-auto max-w-3xl">
      <RichText
        components={{
          img: (props) => (
            <BaseHubImage
              src={props.src ?? ""}
              alt={props.alt ?? ""}
              width={800}
              height={450}
              className="my-6 w-full rounded-lg"
            />
          ),
          h1: ({ children, ...props }) => (
            <h1
