"use server";

import { basehubClient } from "@/lib/basehub";
import { PostFragment, PostMetaFragment } from "@/lib/basehub.fragment";

export async function getAllBlogPosts() {
  const { blog } = await basehubClient.query({
    blog: {
      posts: {
        __args: {
          filter: { isvisible: { eq: "true" } },
          orderBy: "date__DESC",
        },
        items: PostMetaFragment,
      },
    },
  });

  return blog.posts.items;
}

export async function getBlogPost(slug: string) {
  const { blog } = await basehubClient.query({
    blog: {
      posts: {
        __args: { first: 1, filter: { _sys_slug: { eq: slug } } },
        items: PostFragment,
      },
    },
  });

  const [post] = blog.posts.items;
  if (!post?.isvisible) return null;
  return post;
}

export async function getAllBlogSlugs() {
  const { blog } = await basehubClient.query({
    blog: {
      posts: {
        __args: {
          filter: { isvisible: { eq: "true" } },
        },
        items: {
          _slug: true,
        },
      },
    },
  });

  return blog.posts.items.map((post) => ({ slug: post._slug }));
}
